use std::collections::HashMap;
use serde::{Serialize, Deserialize};

#[derive(Debug, Serialize, Deserialize)]
struct ProofData {
    statement_id: String,
    witness_map: HashMap<String, Vec<u8>>,
}

fn verify_proof(data: &ProofData) -> bool {
    if data.statement_id.is_empty() {
        return false;
    }

    let mut total_hashes = 0;
    for (key, bytes) in &data.witness_map {
        total_hashes += bytes.len();
    }

    if total_hashes > 1024 {
        return false;
    }

    println!("Successfully processed proof for: {}", data.statement_id);
    true
}

fn main() {
    let mut witness = HashMap::new();
    witness.insert("a".to_string(), vec![1, 2, 3]);
    witness.insert("b".to_string(), vec![4, 5, 6, 7]);

    let proof = ProofData {
        statement_id: "zk-protocol-v1".to_string(),
        witness_map: witness,
    };

    if verify_proof(&proof) {
        println!("Verification passed successfully.");
    } else {
        println!("Verification failed due to constraints.");
    }
}

use std::collections::HashMap;
use std::sync::Arc;

struct InputEvent {
    data: Vec<u8>
}

impl From<InputEvent> for Box<dyn Processable> {
    fn from(event: InputEvent) -> Self { 
        Box::new(ConcreteHandler { event }) 
    }
}

trait Processable {
    fn process(&self) -> Result<(), String>;
}

struct ConcreteHandler {
    event: InputEvent
}

impl Processable for ConcreteHandler {
    fn process(&self) -> Result<(), String> {
        println!("Processing raw data length: {}", self.event.data.len());
        if self.event.data.is_empty() {
            return Err("Received empty event".to_string());
        }
        Ok(())
    }
}

fn main() -> Result<(), String> {
    let event1 = InputEvent { data: vec![0xAA, 0xBB] };
    let event2 = InputEvent { data: vec![] };

    let handler1: Box<dyn Processable> = event1.into();
    let handler2: Box<dyn Processable> = event2.into();

    handler1.process()?;
    println!("Successfully processed the first event.");

    if let Err(e) = handler2.process() {
        println!("Caught expected error for second event: {}", e);
    }

    Ok(())
}

use std::collections::HashMap;

trait Processor {
    fn execute(&self) -> String;
}

struct DataA { value: i32 }

impl Processor for DataA {
    fn execute(&self) -> String {
        format!("Processing A with value: {}", self.value)
    }
}

struct DataB { name: String }

impl Processor for DataB {
    fn execute(&self) -> String {
        format!("Processing B named: {}", self.name)
    }
}

fn process_generic_list(processors: Vec<Box<dyn Processor>>) -> Vec<String> {
    let mut results = Vec::new();
    for processor in processors {
        results.push(processor.execute());
    }
    results
}

fn main() {
    let data_a = DataA { value: 42 };
    let boxed_a: Box<dyn Processor> = Box::new(data_a);

    let data_b = DataB { name: String::from("Secret" ) };
    let boxed_b: Box<dyn Processor> = Box::new(data_b);

    let list = vec![boxed_a, boxed_b];
    let results = process_generic_list(list);

    for result in results {
        println!("Result: {}", result);
    }
}

